/**
 * ipc-protocol — loader for the Python-generated protocol schema.
 *
 * The schema lives in `ipc-protocol.json` and is regenerated by running
 * `python ipc_protocol.py` at the repo root. This module reads that file
 * once and exposes the protocol metadata plus small helpers for framing
 * commands and parsing events across the stdin/stdout transport.
 *
 * Every line written to the daemon's stdin must be exactly one JSON object
 * with a `cmd` discriminator; every line read from stdout is a JSON object
 * with a `type` discriminator. Line-delimited: no embedded newlines.
 */
'use strict';

const fs = require('node:fs');
const path = require('node:path');

const SCHEMA_PATH = path.join(__dirname, 'ipc-protocol.json');

let _schema = null;

function loadSchema() {
  if (_schema === null) {
    const text = fs.readFileSync(SCHEMA_PATH, 'utf8');
    _schema = JSON.parse(text);
  }
  return _schema;
}

const schema = loadSchema();

const PROTOCOL_VERSION = schema.protocol_version;
const PHASE_NAMES = Object.freeze(schema.phase_names.slice());
const TOTAL_PHASES = schema.total_phases;
const ERROR_TYPES = Object.freeze(schema.error_types.slice());
const WARNING_TYPES = Object.freeze(schema.warning_types.slice());
const COMMAND_NAMES = Object.freeze(Object.keys(schema.commands));
const EVENT_TYPES = Object.freeze(Object.keys(schema.events));

const _commandSet = new Set(COMMAND_NAMES);
const _eventSet = new Set(EVENT_TYPES);

/**
 * Encode a command object as a single JSON line (trailing newline included).
 * `cmd` is required; every other field is passed through untouched. The
 * daemon's `parse_command` rejects unknown fields, so callers should pass
 * only fields listed in the Python dataclass.
 */
function encodeCommand(command) {
  if (!command || typeof command !== 'object') {
    throw new TypeError('encodeCommand: command must be an object');
  }
  if (typeof command.cmd !== 'string') {
    throw new TypeError('encodeCommand: `cmd` is required');
  }
  if (!_commandSet.has(command.cmd)) {
    throw new Error(`encodeCommand: unknown cmd '${command.cmd}'`);
  }
  return JSON.stringify(command) + '\n';
}

/**
 * Parse a single stdout line into an event. Throws on invalid JSON or when
 * the event's `type` is not in the schema.
 */
function parseEvent(line) {
  const trimmed = line.trim();
  if (!trimmed) {
    throw new Error('parseEvent: empty line');
  }
  const event = JSON.parse(trimmed);
  if (!event || typeof event !== 'object' || Array.isArray(event)) {
    throw new Error('parseEvent: line is not a JSON object');
  }
  if (typeof event.type !== 'string') {
    throw new Error("parseEvent: missing `type` discriminator");
  }
  if (!_eventSet.has(event.type)) {
    throw new Error(`parseEvent: unknown event type '${event.type}'`);
  }
  return event;
}

function isValidCommandName(name) {
  return _commandSet.has(name);
}

function isValidEventType(name) {
  return _eventSet.has(name);
}

module.exports = {
  PROTOCOL_VERSION,
  PHASE_NAMES,
  TOTAL_PHASES,
  ERROR_TYPES,
  WARNING_TYPES,
  COMMAND_NAMES,
  EVENT_TYPES,
  encodeCommand,
  parseEvent,
  isValidCommandName,
  isValidEventType,
  schema,
};
